package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.IOException;
import java.io.Reader;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ExtendedBufferedReaderTest {

    private ExtendedBufferedReader reader;

    private Reader mockReader;

    @BeforeEach
    void setUp() {
        mockReader = Mockito.mock(Reader.class);
        reader = new ExtendedBufferedReader(mockReader);
    }

    @Test
    void testReadReturnsCharAndUpdatesLastCharWithoutNewline() throws IOException {
        Mockito.when(mockReader.read()).thenReturn((int) 'a');
        int result = reader.read();
        assertEquals('a', result);
        int lineCounter = getPrivateIntField(reader, "lineCounter");
        assertEquals(0, lineCounter);
        int lastChar = getPrivateIntField(reader, "lastChar");
        assertEquals('a', lastChar);
    }

    @Test
    void testReadReturnsNewlineAndIncrementsLineCounter() throws IOException {
        Mockito.when(mockReader.read()).thenReturn((int) '\n');
        int result = reader.read();
        assertEquals('\n', result);
        int lineCounter = getPrivateIntField(reader, "lineCounter");
        assertEquals(1, lineCounter);
        int lastChar = getPrivateIntField(reader, "lastChar");
        assertEquals('\n', lastChar);
    }

    @Test
    void testReadReturnsEndOfStream() throws IOException {
        Mockito.when(mockReader.read()).thenReturn(ExtendedBufferedReader.END_OF_STREAM);
        int result = reader.read();
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, result);
        int lineCounter = getPrivateIntField(reader, "lineCounter");
        assertEquals(0, lineCounter);
        int lastChar = getPrivateIntField(reader, "lastChar");
        assertEquals(ExtendedBufferedReader.END_OF_STREAM, lastChar);
    }

    private int getPrivateIntField(Object obj, String fieldName) {
        try {
            Field field = ExtendedBufferedReader.class.getDeclaredField(fieldName);
            field.setAccessible(true);
            return field.getInt(obj);
        } catch (Exception e) {
            throw new RuntimeException(e);
        }
    }
}
